cli template.script:
{%- import 'CLI-000-PROJECT-VARIABLES' as project_variables with context -%}
config system interface
  edit "LO_BGP"
    set type loopback
    set vdom "root"
    set ip {{'172.25.0.0'|ipmath(branch_id|int)}} 255.255.255.255
    set allowaccess ping
  next
  edit "LAG_INTERNAL"
    set vdom "root"
    set type aggregate
    set member "port1" "port2"
  next
{%- for vlan_interface in project_variables.interfaces.vlan_interfaces %}
  edit "VL_{{vlan_interface.id}}"
    set vdom "root"
    set type vlan
    set vlanid {{vlan_interface.id}}
    set interface LAG_INTERNAL
    set alias {{vlan_interface.alias}}
    set ip 192.168.{{vlan_interface.suboctet}}.1/24
    {%- if vlan_interface.id == 100 %}
    set allowaccess ping https ssh snmp fgfm
    {%- else %}
    set allowaccess ping
    {%- endif %}
  next
{%- endfor %}
  edit "HUB1-O1"
    set allowaccess ping https ssh
  next
{%- for interface in DEVDB_system_interface %}
  {%- if 'HUB1-02' in interface %}
    edit "HUB1-O2"
      set allowaccess ping https ssh
    next
  {%- endif %}  
{%- endfor %}
end

{%- if cluster %}
config system ha
    set session-pickup enable
    set session-pickup-connectionless enable
    set session-pickup-expectation enable
    set memory-based-failover enable
    set memory-failover-threshold 86
    set memory-failover-flip-timeout 60
    set ha-uptime-diff-margin 60
    {%- for interface in DEVDB_system_interface %}
      {%- if 'HUB1-02' in interface %}
      set monitor {{wan1_port}} {{wan2_port}} LAG_INTERNAL
      {%- else %}
      set monitor {{wan1_port}} LAG_INTERNAL
    {%- endif %}  
  {%- endfor %}
end
config system ha-monitor
    set monitor-vlan enable
end
{%- endif %}

{%- if cluster == "false" %}
config system global
  set hostname {{hostname}}
end
{%- endif %}
